107→type TranslatorSubView = 'translate' | 'history';
108→
109→export function TranslatorView() {
110→  const nav = useNavigation();
111→  const [subView, setSubView] = useState<TranslatorSubView>('translate');
112→  const [sourceText, setSourceText] = useState('');
113→  const [sourceLang, setSourceLang] = useState('auto');
114→  const [targetLang, setTargetLang] = useState('es');
115→  const [detectedLang, setDetectedLang] = useState<string | undefined>();
116→  const [history, setHistory] = useState<TranslationHistoryEntry[]>(() =>
117→    MOCK_HISTORY.map(e => ({ ...e })));
118→  const [historyQuery, setHistoryQuery] = useState('');
119→  const [selectedIndex, setSelectedIndex] = useState(0);
120→  const [actionsOpen, setActionsOpen] = useState(false);
121→  const { items: hudItems, show: showHUD } = useHUD();
122→  const textareaRef = useRef<HTMLTextAreaElement>(null);
123→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
124→  const [translatedText, setTranslatedText] = useState('');
125→
126→  useEffect(() => {
127→    if (debounceRef.current) clearTimeout(debounceRef.current);
128→    if (!sourceText.trim()) {
129→      setTranslatedText('');
130→      setDetectedLang(undefined);
131→      return;
132→    }
133→    debounceRef.current = setTimeout(() => {
134→      const result = mockTranslate(sourceText, sourceLang, targetLang);
135→      setTranslatedText(result.translated);
136→      setDetectedLang(result.detectedLang);
137→    }, 300);
138→    return () => {
139→      if (debounceRef.current) clearTimeout(debounceRef.current);
140→    };
141→  }, [
142→    sourceText,
143→    sourceLang,
144→    targetLang,
145→  ]);
146→
147→  const filteredHistory = useMemo(() => {
148→    if (!historyQuery) return history;
149→    return history.filter(
150→      e =>
151→        fuzzyMatch(historyQuery, e.sourceText) ||
152→        fuzzyMatch(historyQuery, e.translatedText),
153→    );
154→  }, [
155→    history,
156→    historyQuery,
157→  ]);
158→
159→  const sourceLangSections = useMemo(
160→    () => [
161→      {
162→        options: SUPPORTED_LANGUAGES.map(l => ({
