152→function escapeLikeQuery(query: string): string {
153→  return query.replace(/[\\%_]/g, ch => `\\${ch}`);
154→}
155→
156→function escapeFts5Query(query: string): string {
157→  return query
158→    .split(/\s+/)
159→    .filter(Boolean)
160→    .map(token => `"${token.replace(/"/g, '""')}"`)
161→    .join(' ');
162→}
