## 3. COMPONENT VIEW PATTERNS (src/components/floating_notes/floating_notes_view.tsx)

### High-Level Architecture:

**FloatingNotesView Component Structure:**

```typescript
type NoteSubView = 'list' | 'create' | 'edit';

interface EditorViewProps {
  note?: NoteEntry;
  onSave: (title: string, content: string) => void;
}

function NoteEditorView({ note, onSave }: EditorViewProps) {
  // Sub-component for create/edit form
  // Uses useState for form fields
  // Debounced save on changes
  // Keyboard shortcuts (⌘S to save, ⌘⇧P to toggle preview)
}

export function FloatingNotesView() {
  const nav = useNavigation();
  const [entries, setEntries] = useState<NoteEntry[]>([]);
  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [actionsOpen, setActionsOpen] = useState(false);
  const [subView, setSubView] = useState<NoteSubView>('list');
  const [editingNote, setEditingNote] = useState<NoteEntry | undefined>();
  const { items: hudItems, show: showHUD } = useHUD();
  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();

  // Load from DB on mount
  useEffect(() => {
    noteDb.getAll().then(rows => {
      if (rows.length > 0) {
        setEntries(rows.map(rowToEntry));
      } else if (!isTauri) {
        setEntries(MOCK_NOTE_ENTRIES);
      }
    });
  }, []);

  // Search/filter logic
  const dbSearchFn = useCallback((q: string) => noteDb.search(q), []);
  const { results: ftsResults } = useDbSearch(query, dbSearchFn, rowToEntry);
  const filtered = useMemo(() => {
    const items = ftsResults ?? entries;
    if (!ftsResults && query) {
      return items.filter(e => fuzzyMatch(query, e.title) || fuzzyMatch(query, e.content));
    }
    return items;
  }, [entries, query, ftsResults]);

  // Handle keyboard shortcuts
  useKeyboardShortcut({ key: 'Escape' }, handleEscape, { enabled: subView !== 'list' });

  // Conditionally render sub-view or list
  if (subView !== 'list') {
    return (
      <>
        <SearchBar value="" onChange={() => {}} placeholder={formTitle} breadcrumbs={[...nav.breadcrumbs, { label: 'Notes', onBack: handleEscape }]} />
        <div className="command-palette__body">
          <EditorView note={editingNote} onSave={handleSave} />
        </div>
        <ActionPanel contextLabel={formTitle} actions={[...]} />
      </>
    );
  }

  return (
    <>
      <SearchBar value={query} onChange={handleQueryChange} placeholder="Search Notes..." />
      <div className="command-palette__body">
        {filtered.length === 0 ? <EmptyState /> : <List itemCount={filtered.length}>...</List>}
      </div>
      <ActionPanel contextLabel="Notes" actions={[...]} dropdownSections={dropdownSections} />
    </>
  );
}
```

### Conversion Functions:
```typescript
// Convert database row to in-memory entry
function rowToEntry(row: NoteRow): NoteEntry {
  const createdAt = new Date(row.created_at);
  const updatedAt = new Date(row.updated_at);
  return {
    id: row.id,
    title: row.title,
    content: row.content,
    createdAt: isNaN(createdAt.getTime()) ? new Date() : createdAt,
    updatedAt: isNaN(updatedAt.getTime()) ? new Date() : updatedAt,
  };
}

// Convert entry to database row
function entryToRow(entry: NoteEntry): NoteRow {
  return {
    id: entry.id,
    title: entry.title,
    content: entry.content,
    created_at: entry.createdAt.toISOString(),
    updated_at: entry.updatedAt.toISOString(),
  };
}
```

### Key Hooks Used:
- **useNavigation()**: For breadcrumb navigation
- **useHUD()**: For showing notifications ("Note Deleted", etc)
- **useAlert()**: For confirmation dialogs
- **useKeyboardShortcut()**: For keyboard commands
- **useDbSearch()**: For FTS5 database search
- **useState/useEffect/useMemo/useCallback**: Standard React patterns
- **useRef**: For debouncing and ref tracking

---

## 4. FORM COMPONENT PATTERNS (src/components/form/)

### Individual Form Field Components:

**FormField (wrapper for all form fields):**
```typescript
interface FormFieldProps {
  label: string;
