## 6. SECTION RENDERING PATTERN (from FloatingNotesView)

### How Sections are Grouped at Render Time:

```typescript
// Render time calculation
const renderNow = new Date();
const oneDayAgo = renderNow.getTime() - 1000 * 60 * 60 * 24;

const recentItems = filtered.filter(e => e.updatedAt.getTime() > oneDayAgo);
const olderItems = filtered.filter(e => e.updatedAt.getTime() <= oneDayAgo);

// Then render:
<List itemCount={totalItemCount}>
  {(() => {
    const items: ReactNode[] = [];
    let globalIndex = 0;

    if (recentItems.length > 0) {
      items.push(
        <ListSection key="recent" title="Recent">
          {recentItems.map(entry => {
            const idx = globalIndex++;
            return <ListItem key={entry.id} index={idx} ... />;
          })}
        </ListSection>
      );
    }

    if (olderItems.length > 0) {
      items.push(
        <ListSection key="older" title="Older">
          {olderItems.map(entry => {
            const idx = globalIndex++;
            return <ListItem key={entry.id} index={idx} ... />;
          })}
        </ListSection>
      );
    }

    return items;
  })()}
</List>
```

### For Reminders (Overdue, Today, Upcoming, Completed):

```typescript
const renderNow = new Date();
renderNow.setHours(0, 0, 0, 0);

const overdueReminders = filtered.filter(r => !r.completed && new Date(r.dueDate) < renderNow);
const todayReminders = filtered.filter(r => !r.completed && isSameDay(new Date(r.dueDate), renderNow));
const upcomingReminders = filtered.filter(r => !r.completed && new Date(r.dueDate) > renderNow);
const completedReminders = filtered.filter(r => r.completed);
