## 7. KEY STATE MANAGEMENT PATTERNS

### Initialization with Fallback:
```typescript
const [entries, setEntries] = useState<NoteEntry[]>([]);

useEffect(() => {
  let aborted = false;

  noteDb
    .getAll()
    .then(rows => {
      if (aborted) return;
      if (rows.length > 0) {
        setEntries(rows.map(rowToEntry));
      } else if (!isTauri) {
        const mock = MOCK_NOTE_ENTRIES.map(e => ({ ...e }));
        setEntries(mock);
        Promise.all(mock.map(e => noteDb.insert(entryToRow(e)))).catch(console.error);
      }
    })
    .catch(err => {
      console.error('Failed to load notes:', err);
      if (!isTauri && !aborted) {
        setEntries(MOCK_NOTE_ENTRIES.map(e => ({ ...e })));
      }
    });

  return () => {
    aborted = true;
  };
}, []);
```

### Save Logic (Create/Edit):
```typescript
const handleSave = useCallback(
  (title: string, content: string) => {
